package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.Set;

public class Main {

    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        String configContent = Files.readString(Paths.get(args[0]));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configContent);

        BaseSetGenerator baseGen = new BaseSetGenerator(
                config.getNodes(), config.getNumRand());
        List<TestCase> baseSet = baseGen.genBaseSet();

        Tester tester = new Tester(
                config.getFuncName(), args[1], args[2], baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        return ConciseSetGenerator.setCover(results);
    }
}

package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    public String getFuncName() {
        return funcName;
    }

    public List<APyNode<?>> getNodes() {
        return nodes;
    }

    public int getNumRand() {
        return numRand;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;
import java.util.*;

public class ConfigFileParser {

    public ConfigFile parse(String jsonString) throws InvalidConfigException {
        JSONObject json;
        try {
            json = new JSONObject(jsonString);
        } catch (JSONException e) {
            throw new InvalidConfigException("Invalid JSON: " + e.getMessage());
        }

        String fname = extractString(json, "fname");
        JSONArray typesArr = extractStringArray(json, "types");
        JSONArray exDomainsArr = extractStringArray(json, "exhaustive domain");
        JSONArray ranDomainsArr = extractStringArray(json, "random domain");
        int numRand = extractNonNegInt(json, "num random");

        int numTypes = typesArr.length();
        if (exDomainsArr.length() != numTypes) {
            throw new InvalidConfigException("Exhaustive domain length doesn't match types");
        }
        if (ranDomainsArr.length() != numTypes) {
            throw new InvalidConfigException("Random domain length doesn't match types");
        }

        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < numTypes; i++) {
            String typeStr = typesArr.getString(i);
            String exDom = exDomainsArr.getString(i);
            String ranDom = ranDomainsArr.getString(i);

            validateTypeString(typeStr);
            validateDomainString(exDom);
            validateDomainString(ranDom);

            APyNode<?> node = createNode(typeStr, exDom, ranDom);
            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    // ======================== FIELD EXTRACTION ========================

    private String extractString(JSONObject json, String key) throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing field: " + key);
        }
        Object val = json.get(key);
        if (!(val instanceof String)) {
            throw new InvalidConfigException(key + " must be a string");
        }
        return (String) val;
    }

    private JSONArray extractStringArray(JSONObject json, String key)
            throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing field: " + key);
        }
        Object val = json.get(key);
        if (!(val instanceof JSONArray)) {
            throw new InvalidConfigException(key + " must be an array");
        }
        JSONArray arr = (JSONArray) val;
        for (int i = 0; i < arr.length(); i++) {
            if (!(arr.get(i) instanceof String)) {
                throw new InvalidConfigException(key + " must contain only strings");
            }
        }
        return arr;
    }

    private int extractNonNegInt(JSONObject json, String key) throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing field: " + key);
        }
        Object val = json.get(key);
        if (!(val instanceof Integer) && !(val instanceof Long)) {
            throw new InvalidConfigException(key + " must be an integer");
        }
        int intVal = ((Number) val).intValue();
        if (intVal < 0) {
            throw new InvalidConfigException(key + " must be non-negative");
        }
        return intVal;
    }

    // ======================== VALIDATION ========================

    private void validateTypeString(String typeStr) throws InvalidConfigException {
        if (typeStr.contains(" ")) {
            throw new InvalidConfigException("Spurious space in type: " + typeStr);
        }
        validateBalancedParens(typeStr);
    }

    private void validateDomainString(String domain) throws InvalidConfigException {
        int bracketDepth = 0;
        for (int i = 0; i < domain.length(); i++) {
            char c = domain.charAt(i);
            if (c == '[') bracketDepth++;
            else if (c == ']') bracketDepth--;
            else if (c == ' ' && bracketDepth == 0) {
                throw new InvalidConfigException("Spurious space in domain: " + domain);
            }
        }
        validateBalancedParens(domain);
        bracketDepth = 0;
        for (int i = 0; i < domain.length(); i++) {
            char c = domain.charAt(i);
            if (c == '[') bracketDepth++;
            else if (c == ']') bracketDepth--;
            if (bracketDepth < 0) {
                throw new InvalidConfigException("Unbalanced brackets in domain");
            }
        }
        if (bracketDepth != 0) {
            throw new InvalidConfigException("Unbalanced brackets in domain");
        }
    }

    private void validateBalancedParens(String str) throws InvalidConfigException {
        int depth = 0;
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (c == '(') depth++;
            else if (c == ')') depth--;
            if (depth < 0) {
                throw new InvalidConfigException("Unbalanced parentheses");
            }
        }
        if (depth != 0) {
            throw new InvalidConfigException("Unbalanced parentheses");
        }
    }

    // ======================== NODE CREATION ========================

    @SuppressWarnings({"unchecked", "rawtypes"})
    private APyNode<?> createNode(String typeStr, String exDom, String ranDom)
            throws InvalidConfigException {
        // Simple types
        if (typeStr.equals("int")) {
            PyIntNode node = new PyIntNode();
            node.setExDomain(parseSimpleDomain(exDom, "int"));
            node.setRanDomain(parseSimpleDomain(ranDom, "int"));
            return node;
        }
        if (typeStr.equals("bool")) {
            PyBoolNode node = new PyBoolNode();
            node.setExDomain(parseSimpleDomain(exDom, "bool"));
            node.setRanDomain(parseSimpleDomain(ranDom, "bool"));
            return node;
        }
        if (typeStr.equals("float")) {
            PyFloatNode node = new PyFloatNode();
            node.setExDomain(parseSimpleDomain(exDom, "float"));
            node.setRanDomain(parseSimpleDomain(ranDom, "float"));
            return node;
        }

        // Find opening paren for compound types
        int openParen = typeStr.indexOf('(');
        if (openParen == -1) {
            throw new InvalidConfigException("Unknown type: " + typeStr);
        }

        int closeParen = findMatchingParen(typeStr, openParen);
        if (closeParen != typeStr.length() - 1) {
            throw new InvalidConfigException("Spurious characters after type: " + typeStr);
        }

        String outerType = typeStr.substring(0, openParen);
        String innerContent = typeStr.substring(openParen + 1, closeParen);

        // String type
        if (outerType.equals("str")) {
            PyStringNode node = new PyStringNode(innerContent);
            node.setExDomain(parseSimpleDomain(exDom, "size"));
            node.setRanDomain(parseSimpleDomain(ranDom, "size"));
            return node;
        }

        // Collection types: list, set, tuple
        if (outerType.equals("list") || outerType.equals("set")
                || outerType.equals("tuple")) {
            if (hasTopLevelColon(innerContent)) {
                throw new InvalidConfigException("Spurious colon in type: " + typeStr);
            }

            String[] exParts = splitNestedDomain(exDom);
            String[] ranParts = splitNestedDomain(ranDom);

            if (hasTopLevelColon(exParts[1])) {
                throw new InvalidConfigException("Spurious colon in exhaustive domain");
            }
            if (hasTopLevelColon(ranParts[1])) {
                throw new InvalidConfigException("Spurious colon in random domain");
            }

            APyNode innerNode = createNode(innerContent, exParts[1], ranParts[1]);

            APyNode outerNode;
            if (outerType.equals("list")) {
                outerNode = new PyListNode(innerNode);
            } else if (outerType.equals("set")) {
                outerNode = new PySetNode(innerNode);
            } else {
                outerNode = new PyTupleNode(innerNode);
            }

            outerNode.setExDomain(parseSimpleDomain(exParts[0], "size"));
            outerNode.setRanDomain(parseSimpleDomain(ranParts[0], "size"));
            return outerNode;
        }

        // Dict type
        if (outerType.equals("dict")) {
            int colonIdx = findTopLevelColon(innerContent);
            if (colonIdx == -1) {
                throw new InvalidConfigException("Dict type missing key:value separator");
            }
            String keyType = innerContent.substring(0, colonIdx);
            String valType = innerContent.substring(colonIdx + 1);

            String[] exParts = splitNestedDomain(exDom);
            String[] ranParts = splitNestedDomain(ranDom);

            int exColonIdx = findTopLevelColon(exParts[1]);
            if (exColonIdx == -1) {
                throw new InvalidConfigException(
                        "Dict exhaustive domain missing key:value separator");
            }
            int ranColonIdx = findTopLevelColon(ranParts[1]);
            if (ranColonIdx == -1) {
                throw new InvalidConfigException(
                        "Dict random domain missing key:value separator");
            }

            String exKeyDom = exParts[1].substring(0, exColonIdx);
            String exValDom = exParts[1].substring(exColonIdx + 1);
            String ranKeyDom = ranParts[1].substring(0, ranColonIdx);
            String ranValDom = ranParts[1].substring(ranColonIdx + 1);

            APyNode keyNode = createNode(keyType, exKeyDom, ranKeyDom);
            APyNode valNode = createNode(valType, exValDom, ranValDom);

            PyDictNode dictNode = new PyDictNode(keyNode, valNode);
            dictNode.setExDomain(parseSimpleDomain(exParts[0], "size"));
            dictNode.setRanDomain(parseSimpleDomain(ranParts[0], "size"));
            return dictNode;
        }

        throw new InvalidConfigException("Unknown type: " + outerType);
    }

    // ======================== DOMAIN PARSING ========================

    private List<? extends Number> parseSimpleDomain(String domain, String forType)
            throws InvalidConfigException {
        if (domain.startsWith("[")) {
            return parseExplicitArray(domain, forType);
        } else if (domain.contains("~")) {
            return parseRange(domain, forType);
        } else {
            throw new InvalidConfigException("Invalid domain format: " + domain);
        }
    }

    private List<Integer> parseRange(String range, String forType)
            throws InvalidConfigException {
        String[] parts = range.split("~", -1);
        if (parts.length != 2) {
            throw new InvalidConfigException("Invalid range: " + range);
        }

        if (parts[0].contains(".") || parts[1].contains(".")) {
            throw new InvalidConfigException("Range must use integers: " + range);
        }

        int lower, upper;
        try {
            lower = Integer.parseInt(parts[0]);
            upper = Integer.parseInt(parts[1]);
        } catch (NumberFormatException e) {
            throw new InvalidConfigException("Invalid range values: " + range);
        }

        if (lower > upper) {
            throw new InvalidConfigException("Lower bound exceeds upper bound: " + range);
        }

        if (forType.equals("bool")) {
            if (lower < 0 || upper > 1) {
                throw new InvalidConfigException("Bool values must be 0 or 1");
            }
        }
        if (forType.equals("size")) {
            if (lower < 0) {
                throw new InvalidConfigException("Collection size must be non-negative");
            }
        }

        List<Integer> result = new ArrayList<>();
        for (int i = lower; i <= upper; i++) {
            result.add(i);
        }
        return result;
    }

    private List<? extends Number> parseExplicitArray(String arrayStr, String forType)
            throws InvalidConfigException {
        String inner = arrayStr.substring(1, arrayStr.length() - 1).trim();
        if (inner.isEmpty()) {
            return new ArrayList<>();
        }

        String[] parts = inner.split(",");
        LinkedHashSet<Number> values = new LinkedHashSet<>();

        for (String part : parts) {
            String trimmed = part.trim();
            if (trimmed.contains(".")) {
                if (!forType.equals("float")) {
                    throw new InvalidConfigException(
                            "Decimal not allowed for type: " + forType);
                }
                try {
                    values.add(Double.parseDouble(trimmed));
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException("Invalid number: " + trimmed);
                }
            } else {
                int val;
                try {
                    val = Integer.parseInt(trimmed);
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException("Invalid number: " + trimmed);
                }

                if (forType.equals("bool") && (val < 0 || val > 1)) {
                    throw new InvalidConfigException("Bool values must be 0 or 1");
                }
                if (forType.equals("size") && val < 0) {
                    throw new InvalidConfigException(
                            "Collection size must be non-negative");
                }

                values.add(val);
            }
        }

        return new ArrayList<>(values);
    }

    // ======================== HELPER METHODS ========================

    private String[] splitNestedDomain(String domain) throws InvalidConfigException {
        int openParen = -1;
        int bracketDepth = 0;
        for (int i = 0; i < domain.length(); i++) {
            char c = domain.charAt(i);
            if (c == '[') bracketDepth++;
            else if (c == ']') bracketDepth--;
            else if (c == '(' && bracketDepth == 0) {
                openParen = i;
                break;
            }
        }

        if (openParen == -1) {
            throw new InvalidConfigException("Missing nested domain in: " + domain);
        }

        int closeParen = findMatchingParen(domain, openParen);
        if (closeParen != domain.length() - 1) {
            throw new InvalidConfigException(
                    "Spurious characters after domain: " + domain);
        }

        String outerDom = domain.substring(0, openParen);
        String innerDom = domain.substring(openParen + 1, closeParen);

        return new String[]{outerDom, innerDom};
    }

    private int findMatchingParen(String str, int openIndex)
            throws InvalidConfigException {
        int depth = 0;
        for (int i = openIndex; i < str.length(); i++) {
            if (str.charAt(i) == '(') depth++;
            else if (str.charAt(i) == ')') {
                depth--;
                if (depth == 0) return i;
            }
        }
        throw new InvalidConfigException("Unbalanced parentheses in: " + str);
    }

    private int findTopLevelColon(String str) {
        int parenDepth = 0;
        int bracketDepth = 0;
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (c == '(') parenDepth++;
            else if (c == ')') parenDepth--;
            else if (c == '[') bracketDepth++;
            else if (c == ']') bracketDepth--;
            else if (c == ':' && parenDepth == 0 && bracketDepth == 0) {
                return i;
            }
        }
        return -1;
    }

    private boolean hasTopLevelColon(String str) {
        return findTopLevelColon(str) >= 0;
    }
}

